<script setup lang="ts">import { expansionFeature,focusFeature } from '@fex/components-core'; import { createTreeController } from '@fex/components-core/tree/create-tree-controller'; import type { FocusFeatureApi } from '@fex/components-core/tree/features/focus'; import Button from '@fex/components-vue/ui/button'; import Card from '@fex/components-vue/ui/card'; import { ref } from 'vue'; import DemoTree from './demo-tree.vue'; import {departmentFieldNames,departmentTreeData,type DepartmentNode} from './data'; const treeData=ref<readonly DepartmentNode[]>(departmentTreeData); const controller=createTreeController<DepartmentNode>({treeData:departmentTreeData,fieldNames:departmentFieldNames,isLeaf:n=>n.childCount===0,features:[expansionFeature({defaultExpandedKeys:['company','engineering']}),focusFeature()]})</script>
<template><Card title="External controller and node mutation" description="The controller can live outside Tree. Renaming keeps the normalized index and updates only the subscribed node row; structural actions return a new immutable tree through onTreeDataChange."><div class="mb-space-md flex flex-wrap gap-space-sm"><Button size="sm" variant="outline" @click="controller.updateNode('engineering',{name:'Engineering (renamed)'})">Rename Engineering</Button><Button size="sm" variant="outline" @click="controller.insertNode({parentKey:'engineering',node:{id:`api-${Date.now()}`,name:'New API node',childrenList:[],childCount:0}})">Add child</Button><Button size="sm" variant="outline" @click="controller.getFeature<FocusFeatureApi>('focus')?.reveal('design')">Reveal Design</Button></div><DemoTree :controller="controller" :tree-data="treeData" :field-names="departmentFieldNames" :is-leaf="node=>node.childCount===0" :on-tree-data-change="next=>treeData=next" class="max-w-xl rounded-md border border-border bg-background p-space-sm" /></Card></template>
